  "product": "Cosori TurboBlaze Air Fryer",
  "section_1_meta_ads": {
    "ad1": {
      "on_image_text": "Crispy comfort, up to 95% less oil.",
      "primary_text": "Your wellness routine can still make room for crunch. Cosori TurboBlaze air fries with up to 95% less oil than traditional deep frying, helping you turn crispy favorites into lighter home-cooked habits that are easy to come back to.",
